$lang['TF-Help-Step4'] = 'The mobile application must successfully authenticate, and you will be recognized as the user associated with the API key.';
$lang['TF-Help-Step5'] = 'Since the API key has a limited duration, you will need to renew it regularly. Piwigo will notify you by email when one of your API keys expires.';
